  Suburban = 'Suburban',
  Rural = 'Rural'
}

export enum IncomeLevel {
  Low = 'Low',
  Medium = 'Medium',
  High = 'High'
}

export type CustomerSegment = 'High' | 'Medium' | 'Low';

export interface CustomerData {
  id: string;
  age: number;
  gender: Gender;
  location: LocationType;
  incomeLevel: IncomeLevel;
  purchaseFrequency: number;
  avgOrderValue: number;
  recencyDays: number;
  tenureDays: number;
  churned: number;
}

export interface PredictionResult {
  clv: number;
  segment: CustomerSegment;
  confidence: number;
}

export interface BulkPredictionResult {
  summary: {
    totalCustomers: number;
    avgCLV: number;
    highCount: number;
    mediumCount: number;
    lowCount: number;
  };
  details: (CustomerData & { predictedCLV: number; segment: CustomerSegment })[];
}

export interface TrainingMetrics {
  r2Score: number;
  mae: number;
  rmse: number;
  samplesProcessed: number;
}

import { CustomerData, PredictionResult, BulkPredictionResult, TrainingMetrics, Gender, LocationType, IncomeLevel } from '../types';

// Simulate a delay
const delay = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));

export const trainModel = async (): Promise<TrainingMetrics> => {
  await delay(2500); // Simulate training time
  return {
    r2Score: 0.87,
    mae: 45.20,
    rmse: 62.15,
    samplesProcessed: 10000
  };
};

export const predictCLV = async (data: CustomerData): Promise<PredictionResult> => {
  // Simulate inference time (shorter for bulk reuse)
  await delay(100); 

  // A simplified deterministic formula to mimic a RandomForest outcome
  let baseScore = 500;

  // Demographics
  if (data.age > 25 && data.age < 50) baseScore += 100;
  if (data.incomeLevel === IncomeLevel.High) baseScore += 300;
  if (data.incomeLevel === IncomeLevel.Medium) baseScore += 150;

  // Engagement
  baseScore += data.purchaseFrequency * 50; // High frequency is good
  baseScore += data.avgOrderValue * 2.5;    // High AOV is very good
  baseScore += data.tenureDays * 0.5;       // Loyalty bonus

  // Penalties
  baseScore -= data.recencyDays * 2;        // Recent purchase is better (lower recency)
  if (data.churned === 1) baseScore *= 0.2; // Churn significantly kills CLV

  // Location adjustments
  if (data.location === LocationType.Urban) baseScore *= 1.1;

  // Add some "model noise"
  const noise = (Math.random() - 0.5) * 20;
  const finalCLV = Math.max(0, baseScore + noise);

  // Categorization Logic: High, Medium, Low
  let segment: 'High' | 'Medium' | 'Low' = 'Low';

  if (finalCLV >= 1500) {
    segment = 'High';
  } else if (finalCLV >= 500) {
    segment = 'Medium';
  } else {
    segment = 'Low';
  }

  return {
    clv: parseFloat(finalCLV.toFixed(2)),
    segment,
    confidence: 0.85 + (Math.random() * 0.1)
  };
};

export const predictBulk = async (customers: CustomerData[]): Promise<BulkPredictionResult> => {
  await delay(1500); // Simulate bulk processing time

  const details = await Promise.all(customers.map(async (c) => {
    const prediction = await predictCLV(c);
    return {
      ...c,
      predictedCLV: prediction.clv,
      segment: prediction.segment
    };
  }));

  const totalCLV = details.reduce((sum, item) => sum + item.predictedCLV, 0);

  return {
    summary: {
      totalCustomers: customers.length,
      avgCLV: totalCLV / customers.length,
      highCount: details.filter(d => d.segment === 'High').length,
      mediumCount: details.filter(d => d.segment === 'Medium').length,
      lowCount: details.filter(d => d.segment === 'Low').length,
    },
    details
  };
};

