// Simulate a delay
const delay = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));

export const trainModel = async (): Promise<TrainingMetrics> => {
  await delay(2500); // Simulate training time
  return {
    r2Score: 0.87,
    mae: 45.20,
    rmse: 62.15,
    samplesProcessed: 10000
  };
};

export const predictCLV = async (data: CustomerData): Promise<PredictionResult> => {
  // Simulate inference time (shorter for bulk reuse)
  await delay(100); 

  // Equation: CLV = PurchaseFrequency * AvgOrderValue * (TenureDays / 365) * (1 - 0.5 * Churned)
  const tenureYears = data.tenureDays / 365;
  const churnFactor = 1 - (0.5 * data.churned);

  // Calculate Score
  const calculatedScore = data.purchaseFrequency * data.avgOrderValue * tenureYears * churnFactor;

  // Ensure result isn't negative (though inputs shouldn't allow it)
  const finalCLV = Math.max(0, calculatedScore);

  // Categorization Logic: High, Medium, Low
  // Thresholds adjusted slightly for the new multiplicative scale
  // Example: 5 freq * 100 AOV * 1 year * 1 active = 500
  let segment: 'High' | 'Medium' | 'Low' = 'Low';

  if (finalCLV >= 2000) {
    segment = 'High';
  } else if (finalCLV >= 500) {
    segment = 'Medium';
  } else {
    segment = 'Low';
  }

  return {
    clv: parseFloat(finalCLV.toFixed(2)),
    segment,
    confidence: 0.92 + (Math.random() * 0.05) // Higher confidence for deterministic formula
  };
};

export const predictBulk = async (customers: CustomerData[]): Promise<BulkPredictionResult> => {
  await delay(1500); // Simulate bulk processing time

  const details = await Promise.all(customers.map(async (c) => {
    const prediction = await predictCLV(c);
    return {
      ...c,
      predictedCLV: prediction.clv,
      segment: prediction.segment
    };
  }));

  const totalCLV = details.reduce((sum, item) => sum + item.predictedCLV, 0);

  return {
    summary: {
      totalCustomers: customers.length,
      avgCLV: totalCLV / customers.length,
      highCount: details.filter(d => d.segment === 'High').length,
      mediumCount: details.filter(d => d.segment === 'Medium').length,
      lowCount: details.filter(d => d.segment === 'Low').length,
    },
    details
  };
};

// Generate Mock Data for the Table
export const generateMockDataset = (count: number): CustomerData[] => {
  return Array.from({ length: count }).map((_, i) => ({
    id: `CUST-${Math.random().toString(36).substr(2, 6).toUpperCase()}`,
    age: 20 + Math.floor(Math.random() * 50),
    gender: Math.random() > 0.5 ? Gender.Male : Gender.Female,
    location: [LocationType.Urban, LocationType.Suburban, LocationType.Rural][Math.floor(Math.random() * 3)],
    incomeLevel: [IncomeLevel.Low, IncomeLevel.Medium, IncomeLevel.High][Math.floor(Math.random() * 3)],
    purchaseFrequency: 1 + Math.random() * 10,
    avgOrderValue: 50 + Math.random() * 200,
    recencyDays: Math.floor(Math.random() * 100),
    tenureDays: Math.floor(Math.random() * 1000), // 0 to ~2.7 years
    churned: Math.random() > 0.8 ? 1 : 0
  }));
};

