                <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
              </svg>
            )}
            {isLoading ? 'Predicting CLV...' : 'Run Single Prediction'}
          </button>
        </form>
      ) : (
        <div className="space-y-6">
          <div className="border-2 border-dashed border-slate-300 rounded-lg p-8 text-center bg-slate-50 hover:bg-slate-100 transition-colors cursor-pointer group" onClick={() => setBulkFile('data.csv')}>
            <UploadCloud className="w-10 h-10 text-slate-400 mx-auto mb-2 group-hover:text-indigo-500" />
            <p className="text-sm font-medium text-slate-600">
              {bulkFile ? <span className="text-emerald-600 font-bold">customers_batch_2024.csv selected</span> : 'Click to simulate CSV Upload'}
            </p>
            <p className="text-xs text-slate-400 mt-1">Supports .csv (Max 50MB)</p>
          </div>

          <button 
            onClick={handleBulkSimulate}
            disabled={isLoading || !isEnabled || !bulkFile}
            className="w-full bg-indigo-600 text-white font-semibold py-3 rounded-lg shadow-md hover:bg-indigo-700 focus:outline-none focus:ring-2 focus:ring-indigo-500 focus:ring-offset-2 disabled:opacity-50 flex items-center justify-center gap-2"
          >
             {isLoading && (
              <svg className="animate-spin h-5 w-5 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
              </svg>
            )}
            {isLoading ? 'Processing Batch...' : 'Run Bulk Prediction'}
          </button>
        </div>
      )}
    </div>
  );
};

