            <p className="text-sm font-semibold text-slate-700">
              {bulkFile ? <span className="text-emerald-600">customers_batch_2024.csv selected</span> : 'Drop CSV file or click to browse'}
            </p>
            <p className="text-xs text-slate-400 mt-2 max-w-xs mx-auto">Supports .csv files with standard customer headers. Max file size 50MB.</p>
          </div>

          <button 
            onClick={handleBulkSimulate}
            disabled={isLoading || !isEnabled || !bulkFile}
             className="w-full bg-indigo-600 text-white font-bold py-4 rounded-xl shadow-lg shadow-indigo-200 hover:bg-indigo-700 hover:shadow-xl hover:-translate-y-0.5 focus:outline-none focus:ring-2 focus:ring-indigo-500 focus:ring-offset-2 disabled:opacity-50 disabled:shadow-none disabled:translate-y-0 transition-all flex items-center justify-center gap-2"
          >
             {isLoading && (
              <svg className="animate-spin h-5 w-5 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
              </svg>
            )}
            {isLoading ? 'Processing Batch Job...' : 'Run Batch Prediction'}
          </button>
        </div>
      )}
    </div>
  );
};

export default PredictionForm;

