import React, { useState, useEffect } from 'react';
import { TrainingMetrics, CustomerData } from '../types';
import { trainModel, generateMockDataset } from '../services/mlService';
import { Database, Play, CheckCircle, Activity, BarChart3, Binary } from 'lucide-react';

interface TrainingPanelProps {
  onTrainingComplete: () => void;
}

const TrainingPanel: React.FC<TrainingPanelProps> = ({ onTrainingComplete }) => {
  const [isTraining, setIsTraining] = useState(false);
  const [progress, setProgress] = useState(0);
  const [metrics, setMetrics] = useState<TrainingMetrics | null>(null);
  const [dataset, setDataset] = useState<CustomerData[]>([]);

  useEffect(() => {
    setDataset(generateMockDataset(5));
  }, []);

  const handleTrain = async () => {
    setIsTraining(true);
    setProgress(0);
    const interval = setInterval(() => {
      setProgress((prev) => (prev >= 90 ? prev : prev + 10));
    }, 200);

    try {
      const results = await trainModel();
      clearInterval(interval);
      setProgress(100);
      setMetrics(results);
      onTrainingComplete();
    } catch (error) {
      console.error(error);
    } finally {
      setIsTraining(false);
    }
  };

  return (
    <div className="card-base p-8 relative overflow-hidden">
      {/* Header */}
      <div className="flex items-start justify-between mb-8">
        <div>
          <div className="flex items-center gap-3 mb-1">
             <div className="bg-indigo-600 p-2 rounded-lg shadow-sm">
               <Database size={20} className="text-white" />
             </div>
             <h2 className="text-xl font-bold text-slate-900">Data Ingestion & Training</h2>
          </div>
          <p className="text-sm font-medium text-slate-500 ml-11">
            Preprocess features and train Random Forest Regressor.
          </p>
        </div>
        {metrics && (
           <span className="flex items-center gap-1.5 bg-emerald-100 text-emerald-800 px-3 py-1.5 rounded-full text-xs font-bold border border-emerald-200 shadow-sm">
             <CheckCircle size={14} className="text-emerald-700"/> Ready for Inference
           </span>
        )}
      </div>

      {/* Raw Data Preview */}
      <div className="mb-8">
        <div className="flex justify-between items-center mb-3">
          <h3 className="text-xs font-bold text-slate-500 uppercase tracking-wider flex items-center gap-2">
            <Binary size={14} className="text-indigo-500" /> Feature Store Preview
          </h3>
          <span className="text-[10px] font-mono font-medium bg-slate-100 text-slate-600 px-2 py-1 rounded border border-slate-200">
            source: s3://data-lake/customers_v2.csv
          </span>
        </div>
        <div className="overflow-hidden border border-slate-200 rounded-lg shadow-sm">
          <table className="w-full text-sm text-left">
            <thead className="text-xs text-slate-700 uppercase bg-slate-50 border-b border-slate-200 font-bold">
              <tr>
                <th className="px-4 py-3">Age</th>
                <th className="px-4 py-3">Location</th>
                <th className="px-4 py-3">Income Tier</th>
                <th className="px-4 py-3">Freq/Mo</th>
                <th className="px-4 py-3">AOV</th>
                <th className="px-4 py-3">Tenure</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100 bg-white">
              {dataset.map((row, idx) => (
                <tr key={idx} className="hover:bg-slate-50 transition-colors">
                  <td className="px-4 py-2.5 font-mono text-xs text-slate-600">{row.age}</td>
                  <td className="px-4 py-2.5 text-slate-900">{row.location}</td>
                  <td className="px-4 py-2.5">
                    <span className={`text-[10px] px-2 py-0.5 rounded-full font-bold uppercase tracking-wide border ${
                        row.incomeLevel === 'High' ? 'bg-purple-50 text-purple-700 border-purple-100' :
                        row.incomeLevel === 'Medium' ? 'bg-blue-50 text-blue-700 border-blue-100' : 'bg-slate-100 text-slate-600 border-slate-200'
                    }`}>{row.incomeLevel}</span>
                  </td>
                  <td className="px-4 py-2.5 text-slate-900 font-medium">{row.purchaseFrequency.toFixed(1)}</td>
                  <td className="px-4 py-2.5 font-bold text-slate-900">${row.avgOrderValue.toFixed(0)}</td>
                  <td className="px-4 py-2.5 text-slate-600">{row.tenureDays}d</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      {/* Action Area */}
      <div className="space-y-6">
        <button
          onClick={handleTrain}
          disabled={isTraining || !!metrics}
          className={`w-full group relative overflow-hidden px-6 py-4 rounded-xl font-bold text-white shadow-md transition-all duration-200 focus:outline-none focus:ring-2 focus:ring-offset-2
            ${isTraining ? 'bg-slate-800 cursor-not-allowed' : 
              metrics ? 'bg-emerald-600 hover:bg-emerald-700 shadow-emerald-200 focus:ring-emerald-500' : 'bg-indigo-600 hover:bg-indigo-700 shadow-indigo-200 focus:ring-indigo-500 hover:-translate-y-0.5'}
          `}
        >
          <span className="relative z-10 flex items-center justify-center gap-2">
            {isTraining ? <Activity className="animate-spin" size={20} /> : metrics ? <CheckCircle size={20} /> : <Play size={20} fill="currentColor" />}
            {isTraining ? 'Training Pipeline Running...' : metrics ? 'Model Successfully Trained' : 'Initialize Training Run'}
          </span>
          {isTraining && (
              <div className="absolute bottom-0 left-0 h-1 bg-indigo-400 transition-all duration-300" style={{ width: `${progress}%` }}></div>
          )}
