        {/* Metrics Grid */}
        {metrics && (
          <div className="grid grid-cols-3 gap-4 animate-in fade-in slide-in-from-bottom-4 duration-500">
            <div className="bg-emerald-50 border border-emerald-100 p-4 rounded-xl flex flex-col items-center text-center hover:shadow-sm transition-shadow">
              <span className="text-emerald-600 mb-2"><Activity size={20} /></span>
              <p className="text-[10px] text-emerald-800 uppercase font-black tracking-wider">R² Score</p>
              <p className="text-2xl font-black text-emerald-700 mt-1">{metrics.r2Score}</p>
            </div>
            <div className="bg-indigo-50 border border-indigo-100 p-4 rounded-xl flex flex-col items-center text-center hover:shadow-sm transition-shadow">
              <span className="text-indigo-600 mb-2"><BarChart3 size={20} /></span>
              <p className="text-[10px] text-indigo-800 uppercase font-black tracking-wider">MAE</p>
              <p className="text-2xl font-black text-indigo-700 mt-1">${metrics.mae}</p>
            </div>
            <div className="bg-slate-50 border border-slate-200 p-4 rounded-xl flex flex-col items-center text-center hover:shadow-sm transition-shadow">
              <span className="text-slate-600 mb-2"><Database size={20} /></span>
              <p className="text-[10px] text-slate-800 uppercase font-black tracking-wider">RMSE</p>
              <p className="text-2xl font-black text-slate-700 mt-1">{metrics.rmse}</p>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default TrainingPanel;

import React, { useState } from 'react';
import { CustomerData, Gender, LocationType, IncomeLevel, PredictionResult, BulkPredictionResult } from '../types';
import { predictCLV, predictBulk, generateMockDataset } from '../services/mlService';
import { FileSpreadsheet, User, UploadCloud, Calculator, ArrowRight } from 'lucide-react';

interface PredictionFormProps {
  onSingleResult: (result: PredictionResult) => void;
  onBulkResult: (result: BulkPredictionResult) => void;
  isEnabled: boolean;
}

const PredictionForm: React.FC<PredictionFormProps> = ({ onSingleResult, onBulkResult, isEnabled }) => {
  const [mode, setMode] = useState<'single' | 'bulk'>('single');
  const [isLoading, setIsLoading] = useState(false);

  // Single Form State
  const [formData, setFormData] = useState<CustomerData>({
    id: 'NEW-001',
    age: 30,
    gender: Gender.Female,
    location: LocationType.Urban,
    incomeLevel: IncomeLevel.Medium,
    purchaseFrequency: 5.0,
    avgOrderValue: 120.0,
    recencyDays: 10,
    tenureDays: 365,
    churned: 0
  });

  const [bulkFile, setBulkFile] = useState<string | null>(null);

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: (name === 'age' || name === 'recencyDays' || name === 'tenureDays' || name === 'churned') 
        ? parseInt(value) 
        : (name === 'purchaseFrequency' || name === 'avgOrderValue') 
          ? parseFloat(value) 
          : value
    }));
  };

  const handleSingleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!isEnabled) return;
    setIsLoading(true);
    try {
      const result = await predictCLV(formData);
      onSingleResult(result);
    } finally {
      setIsLoading(false);
    }
  };

  const handleBulkSimulate = async () => {
    if (!isEnabled) return;
    setIsLoading(true);
    try {
      const mockBatch = generateMockDataset(50);
      const result = await predictBulk(mockBatch);
      onBulkResult(result);
    } finally {
      setIsLoading(false);
    }
  };

  const inputClass = "w-full bg-white border border-slate-300 rounded-lg px-3 py-2.5 text-sm font-medium text-slate-900 focus:outline-none focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 transition-all disabled:bg-slate-100 disabled:text-slate-400 placeholder-slate-400 hover:border-slate-400";
  const labelClass = "block text-xs font-bold text-slate-700 mb-1.5 uppercase tracking-wide";

  return (
    <div className={`card-base p-8 transition-all duration-500 ${!isEnabled ? 'opacity-50 blur-[1px] pointer-events-none grayscale' : 'opacity-100'}`}>
      <div className="flex items-center gap-3 mb-6">
        <div className="bg-purple-600 p-2 rounded-lg shadow-sm">
           <Calculator size={20} className="text-white" />
        </div>
        <div>
            <h2 className="text-xl font-bold text-slate-900">Prediction Pipeline</h2>
            <p className="text-sm font-medium text-slate-500">Inference engine configuration</p>
        </div>
      </div>

      {/* Modern Segmented Toggle */}
      <div className="bg-slate-100 p-1.5 rounded-xl flex mb-8 relative border border-slate-200">
        <div 
          className={`absolute top-1.5 bottom-1.5 w-[calc(50%-6px)] bg-white rounded-lg shadow-sm border border-slate-200 transition-all duration-300 ease-spring ${mode === 'bulk' ? 'translate-x-[calc(100%+6px)]' : 'translate-x-0'}`}
        />
        <button
          onClick={() => setMode('single')}
          className={`relative z-10 flex-1 flex items-center justify-center gap-2 py-2 text-sm font-bold rounded-lg transition-colors duration-300
            ${mode === 'single' ? 'text-indigo-700' : 'text-slate-500 hover:text-slate-700'}`}
        >
          <User size={16} /> Individual
        </button>
        <button
          onClick={() => setMode('bulk')}
          className={`relative z-10 flex-1 flex items-center justify-center gap-2 py-2 text-sm font-bold rounded-lg transition-colors duration-300
            ${mode === 'bulk' ? 'text-indigo-700' : 'text-slate-500 hover:text-slate-700'}`}
        >
          <FileSpreadsheet size={16} /> Batch Upload
        </button>
      </div>

      {mode === 'single' ? (
        <form onSubmit={handleSingleSubmit} className="space-y-8 animate-in fade-in slide-in-from-left-4 duration-300">
           {/* Demographics Group */}
        <div className="bg-slate-50 p-5 rounded-xl border border-slate-200">
          <h3 className="text-xs font-black text-indigo-600 uppercase tracking-wider mb-4 border-b border-indigo-100 pb-2">Customer Profile</h3>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-5">
            <div>
              <label className={labelClass}>Age</label>
              <input type="number" name="age" value={formData.age} onChange={handleChange} className={inputClass} />
            </div>
            <div>
              <label className={labelClass}>Gender</label>
              <div className="relative">
                <select name="gender" value={formData.gender} onChange={handleChange} className={`${inputClass} appearance-none`}>
                    {Object.values(Gender).map(g => <option key={g} value={g}>{g}</option>)}
                </select>
                <div className="absolute right-3 top-3 pointer-events-none text-slate-500">
                   <ArrowRight size={14} className="rotate-90"/>
                </div>
              </div>
            </div>
            <div>
              <label className={labelClass}>Location</label>
              <div className="relative">
                <select name="location" value={formData.location} onChange={handleChange} className={`${inputClass} appearance-none`}>
                    {Object.values(LocationType).map(l => <option key={l} value={l}>{l}</option>)}
                </select>
                <div className="absolute right-3 top-3 pointer-events-none text-slate-500">
                   <ArrowRight size={14} className="rotate-90"/>
                </div>
              </div>
            </div>
            <div>
              <label className={labelClass}>Income Bracket</label>
              <div className="relative">
                <select name="incomeLevel" value={formData.incomeLevel} onChange={handleChange} className={`${inputClass} appearance-none`}>
                    {Object.values(IncomeLevel).map(i => <option key={i} value={i}>{i}</option>)}
                </select>
                <div className="absolute right-3 top-3 pointer-events-none text-slate-500">
                   <ArrowRight size={14} className="rotate-90"/>
                </div>
              </div>
            </div>
          </div>
        </div>

        {/* Behavior Group */}
        <div className="bg-slate-50 p-5 rounded-xl border border-slate-200">
          <h3 className="text-xs font-black text-indigo-600 uppercase tracking-wider mb-4 border-b border-indigo-100 pb-2">Behavioral Metrics</h3>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-5">
             <div>
              <label className={labelClass}>Orders / Month</label>
              <input type="number" step="0.1" name="purchaseFrequency" value={formData.purchaseFrequency} onChange={handleChange} className={inputClass} />
            </div>
            <div>
              <label className={labelClass}>Avg Order Value ($)</label>
              <input type="number" step="0.01" name="avgOrderValue" value={formData.avgOrderValue} onChange={handleChange} className={inputClass} />
            </div>
            <div>
              <label className={labelClass}>Recency (days)</label>
              <input type="number" name="recencyDays" value={formData.recencyDays} onChange={handleChange} className={inputClass} />
            </div>
            <div>
              <label className={labelClass}>Total Tenure (days)</label>
              <input type="number" name="tenureDays" value={formData.tenureDays} onChange={handleChange} className={inputClass} />
            </div>
            <div className="md:col-span-2">
              <label className={labelClass}>Current Status</label>
              <div className="flex gap-4 mt-1">
                 <label className={`flex-1 cursor-pointer border rounded-lg p-3 flex items-center justify-center gap-2 transition-all shadow-sm ${formData.churned === 0 ? 'bg-emerald-50 border-emerald-300 text-emerald-800 font-bold ring-1 ring-emerald-500/20' : 'bg-white border-slate-300 text-slate-600 hover:border-slate-400'}`}>
                    <input type="radio" name="churned" value={0} checked={formData.churned === 0} onChange={() => setFormData(prev => ({...prev, churned: 0}))} className="hidden"/>
                    <span className="w-2.5 h-2.5 rounded-full bg-emerald-500 ring-2 ring-emerald-100"></span> Active
                 </label>
                 <label className={`flex-1 cursor-pointer border rounded-lg p-3 flex items-center justify-center gap-2 transition-all shadow-sm ${formData.churned === 1 ? 'bg-red-50 border-red-300 text-red-800 font-bold ring-1 ring-red-500/20' : 'bg-white border-slate-300 text-slate-600 hover:border-slate-400'}`}>
                    <input type="radio" name="churned" value={1} checked={formData.churned === 1} onChange={() => setFormData(prev => ({...prev, churned: 1}))} className="hidden"/>
                    <span className="w-2.5 h-2.5 rounded-full bg-red-500 ring-2 ring-red-100"></span> Churned
                 </label>
              </div>
            </div>
          </div>
        </div>

          <button 
            type="submit" 
            disabled={isLoading || !isEnabled}
            className="w-full bg-indigo-600 text-white font-bold py-4 rounded-xl shadow-lg shadow-indigo-200 hover:bg-indigo-700 hover:shadow-xl hover:-translate-y-0.5 focus:outline-none focus:ring-2 focus:ring-indigo-500 focus:ring-offset-2 disabled:opacity-50 disabled:shadow-none disabled:translate-y-0 transition-all flex items-center justify-center gap-2"
          >
            {isLoading && (
              <svg className="animate-spin h-5 w-5 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
              </svg>
            )}
            {isLoading ? 'Running Inference...' : 'Generate Prediction'}
          </button>
        </form>
      ) : (
        <div className="space-y-6 animate-in fade-in slide-in-from-right-4 duration-300">
          <div 
            className={`border-2 border-dashed rounded-xl p-10 text-center transition-all cursor-pointer group
                ${bulkFile ? 'border-emerald-500 bg-emerald-50/50' : 'border-slate-300 bg-slate-50 hover:bg-white hover:border-indigo-400'}
