            onClick={() => setBulkFile('data.csv')}
          >
            <div className={`w-16 h-16 rounded-full mx-auto mb-4 flex items-center justify-center transition-colors shadow-sm border ${bulkFile ? 'bg-emerald-100 text-emerald-600 border-emerald-200' : 'bg-white text-slate-400 border-slate-200 group-hover:border-indigo-200 group-hover:text-indigo-500'}`}>
                <UploadCloud className="w-8 h-8" />
