            <p className="text-sm font-bold text-slate-800">
              {bulkFile ? <span className="text-emerald-700">customers_batch_2024.csv selected</span> : 'Drop CSV file or click to browse'}
            </p>
            <p className="text-xs text-slate-500 mt-2 max-w-xs mx-auto font-medium">Supports .csv files with standard customer headers. Max file size 50MB.</p>
          </div>

          <button 
