import React, { useState, useRef } from 'react';
import { CustomerData, Gender, LocationType, IncomeLevel, PredictionResult, BulkPredictionResult, Industry, SegmentationThresholds } from '../types';
import { predictCLV, predictBulk, generateMockDataset } from '../services/mlService';
import { FileSpreadsheet, User, UploadCloud, Settings, Sliders, ChevronDown } from 'lucide-react';

interface PredictionFormProps {
  onSingleResult: (result: PredictionResult) => void;
  onBulkResult: (result: BulkPredictionResult) => void;
  isEnabled: boolean;
}

const PRESETS: Record<Industry, SegmentationThresholds> = {
  'Generic': { medium: 500, high: 2000 },
  'Fashion': { medium: 300, high: 1000 },     // High freq, lower value items
  'Electronics': { medium: 800, high: 2500 }, // Low freq, high value items
  'SaaS': { medium: 1000, high: 5000 }        // Recurring revenue focus
};

const PredictionForm: React.FC<PredictionFormProps> = ({ onSingleResult, onBulkResult, isEnabled }) => {
  const [mode, setMode] = useState<'single' | 'bulk'>('single');
  const [isLoading, setIsLoading] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Configuration State
  const [industry, setIndustry] = useState<Industry>('Generic');
  const [thresholds, setThresholds] = useState<SegmentationThresholds>(PRESETS['Generic']);
  const [isConfigOpen, setIsConfigOpen] = useState(false);

  // Single Form State
  const [formData, setFormData] = useState<CustomerData>({
    id: 'NEW-001',
    age: 30,
    gender: Gender.Female,
    location: LocationType.Urban,
    incomeLevel: IncomeLevel.Medium,
    purchaseFrequency: 5.0,
    avgOrderValue: 120.0,
    recencyDays: 10,
    tenureDays: 365,
    churned: 0
  });

  // Bulk Form State
  const [bulkFile, setBulkFile] = useState<string | null>(null);

  const handleIndustryChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
    const newIndustry = e.target.value as Industry;
    setIndustry(newIndustry);
    setThresholds(PRESETS[newIndustry]);
  };

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: (name === 'age' || name === 'recencyDays' || name === 'tenureDays' || name === 'churned') 
        ? parseInt(value) 
        : (name === 'purchaseFrequency' || name === 'avgOrderValue') 
          ? parseFloat(value) 
          : value
    }));
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      setBulkFile(file.name);
    }
  };

  const handleSingleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!isEnabled) return;

    setIsLoading(true);
    try {
      // Pass dynamic thresholds
      const result = await predictCLV(formData, thresholds);
      onSingleResult(result);
    } finally {
      setIsLoading(false);
    }
  };

  const handleBulkSimulate = async () => {
    if (!isEnabled) return;
    setIsLoading(true);
    try {
      // Simulate reading a CSV file by generating data
      const mockBatch = generateMockDataset(50); // Simulate 50 rows
      // Pass dynamic thresholds
      const result = await predictBulk(mockBatch, thresholds);
      onBulkResult(result);
    } finally {
      setIsLoading(false);
    }
  };

  const inputClass = "w-full border border-black bg-slate-50 rounded-md px-3 py-2 text-sm text-black focus:outline-none focus:ring-2 focus:ring-indigo-500 disabled:bg-slate-100 disabled:text-slate-400";
  const labelClass = "block text-xs font-medium text-slate-700 mb-1";

  return (
    <div className={`bg-white p-6 rounded-xl shadow-sm border border-slate-200 transition-opacity ${!isEnabled ? 'opacity-50 pointer-events-none' : 'opacity-100'}`}>
      <div className="border-b border-slate-100 pb-4 mb-6">
        <h2 className="text-xl font-semibold text-slate-800">2. Prediction Pipeline</h2>
        <p className="text-sm text-slate-500 mt-1">
          Select input method to project Customer Lifetime Value Score.
        </p>
      </div>

      {/* Configuration Panel */}
      <div className="mb-6 bg-slate-50 rounded-lg border border-slate-200 p-4">
        <div className="flex justify-between items-center">
          <div className="flex items-center gap-2">
            <Settings className="w-4 h-4 text-indigo-600" />
            <span className="text-sm font-semibold text-slate-700">Segmentation Logic</span>
          </div>
          <button onClick={() => setIsConfigOpen(!isConfigOpen)} className="text-xs text-indigo-600 font-medium hover:text-indigo-800 hover:underline flex items-center gap-1 transition-colors">
            {isConfigOpen ? 'Hide Controls' : 'Customize'} <Sliders size={12}/>
          </button>
        </div>

        <div className="mt-3">
          {!isConfigOpen && (
             <div className="flex justify-between items-center text-xs text-slate-500">
               <div className="flex items-center gap-2">
                 <span className="font-medium text-slate-700">{industry} Mode:</span>
                 <span>Medium &gt; ${thresholds.medium}</span>
                 <span>High &gt; ${thresholds.high}</span>
               </div>
             </div>
          )}

          <div className={`space-y-4 overflow-hidden transition-all duration-300 ease-in-out ${isConfigOpen ? 'max-h-96 opacity-100 mt-4 pt-4 border-t border-slate-200' : 'max-h-0 opacity-0'}`}>
             <div>
                <label className="text-xs font-medium text-slate-500 block mb-1">Industry Context (Applies Presets)</label>
                <div className="relative">
                  <select 
                    value={industry} 
                    onChange={handleIndustryChange} 
                    className="w-full text-sm border border-slate-300 rounded-md shadow-sm px-3 py-2 bg-white focus:outline-none focus:border-indigo-500 focus:ring-1 focus:ring-indigo-500 appearance-none"
                  >
                    {Object.keys(PRESETS).map(k => <option key={k} value={k}>{k}</option>)}
                  </select>
                  <ChevronDown className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-400 w-4 h-4 pointer-events-none" />
                </div>
              </div>

              {/* Sliders */}
              <div className="space-y-4">
                <div>
                  <div className="flex justify-between text-xs mb-1">
                    <label className="font-medium text-slate-600">Medium Value Threshold</label>
                    <span className="font-bold text-amber-600">${thresholds.medium}</span>
                  </div>
                  <input type="range" min="0" max={thresholds.high} step="50" 
                      value={thresholds.medium}
                      onChange={(e) => setThresholds(prev => ({...prev, medium: Number(e.target.value)}))}
                      className="w-full h-2 bg-slate-200 rounded-lg appearance-none cursor-pointer accent-amber-500"
                  />
                  <p className="text-[10px] text-slate-400 mt-1">Customers with CLV above ${thresholds.medium} are marked Medium.</p>
                </div>
                <div>
                  <div className="flex justify-between text-xs mb-1">
                    <label className="font-medium text-slate-600">High Value Threshold</label>
                    <span className="font-bold text-emerald-600">${thresholds.high}</span>
                  </div>
                  <input type="range" min={thresholds.medium} max="10000" step="100" 
                      value={thresholds.high}
                      onChange={(e) => setThresholds(prev => ({...prev, high: Number(e.target.value)}))}
                      className="w-full h-2 bg-slate-200 rounded-lg appearance-none cursor-pointer accent-emerald-500"
                  />
                   <p className="text-[10px] text-slate-400 mt-1">Customers with CLV above ${thresholds.high} are marked High.</p>
                </div>
              </div>
          </div>
        </div>
      </div>

      {/* Mode Toggles */}
      <div className="flex p-1 bg-slate-100 rounded-lg mb-6">
        <button
          onClick={() => setMode('single')}
          className={`flex-1 flex items-center justify-center gap-2 py-2 text-sm font-medium rounded-md transition-all
            ${mode === 'single' ? 'bg-white text-indigo-700 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
        >
          <User size={16} /> Single Customer
        </button>
        <button
          onClick={() => setMode('bulk')}
          className={`flex-1 flex items-center justify-center gap-2 py-2 text-sm font-medium rounded-md transition-all
            ${mode === 'bulk' ? 'bg-white text-indigo-700 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
        >
          <FileSpreadsheet size={16} /> Bulk Upload
        </button>
      </div>

      {mode === 'single' ? (
        <form onSubmit={handleSingleSubmit} className="space-y-6">
           {/* Demographics */}
        <div className="space-y-4">
          <h3 className="text-sm font-semibold text-indigo-600 uppercase tracking-wide">Demographics</h3>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div>
              <label className={labelClass}>Age</label>
              <input type="number" name="age" value={formData.age} onChange={handleChange} className={inputClass} />
            </div>
            <div>
              <label className={labelClass}>Gender</label>
              <select name="gender" value={formData.gender} onChange={handleChange} className={inputClass}>
                {Object.values(Gender).map(g => <option key={g} value={g}>{g}</option>)}
              </select>
            </div>
            <div>
              <label className={labelClass}>Location</label>
              <select name="location" value={formData.location} onChange={handleChange} className={inputClass}>
                {Object.values(LocationType).map(l => <option key={l} value={l}>{l}</option>)}
              </select>
            </div>
            <div>
              <label className={labelClass}>Income Level</label>
              <select name="incomeLevel" value={formData.incomeLevel} onChange={handleChange} className={inputClass}>
                {Object.values(IncomeLevel).map(i => <option key={i} value={i}>{i}</option>)}
              </select>
            </div>
          </div>
        </div>

        {/* Behavior */}
        <div className="space-y-4">
          <h3 className="text-sm font-semibold text-indigo-600 uppercase tracking-wide">Behavioral Data</h3>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
             <div>
              <label className={labelClass}>Purchase Freq (orders/month)</label>
              <input type="number" step="0.1" name="purchaseFrequency" value={formData.purchaseFrequency} onChange={handleChange} className={inputClass} />
            </div>
            <div>
              <label className={labelClass}>Avg Order Value ($)</label>
              <input type="number" step="0.01" name="avgOrderValue" value={formData.avgOrderValue} onChange={handleChange} className={inputClass} />
            </div>
            <div>
              <label className={labelClass}>Recency (days ago)</label>
              <input type="number" name="recencyDays" value={formData.recencyDays} onChange={handleChange} className={inputClass} />
            </div>
            <div>
              <label className={labelClass}>Tenure (days)</label>
              <input type="number" name="tenureDays" value={formData.tenureDays} onChange={handleChange} className={inputClass} />
            </div>
            <div className="md:col-span-2">
              <label className={labelClass}>Churn Status</label>
              <select name="churned" value={formData.churned} onChange={handleChange} className={inputClass}>
                <option value={0}>Active</option>
                <option value={1}>Churned</option>
              </select>
            </div>
          </div>
        </div>

          <button 
            type="submit" 
            disabled={isLoading || !isEnabled}
            className="w-full bg-indigo-600 text-white font-semibold py-3 rounded-lg shadow-md hover:bg-indigo-700 focus:outline-none focus:ring-2 focus:ring-indigo-500 focus:ring-offset-2 disabled:opacity-50 flex items-center justify-center gap-2"
          >
            {isLoading && (
              <svg className="animate-spin h-5 w-5 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
              </svg>
            )}
            {isLoading ? 'Predicting CLV...' : 'Run Single Prediction'}
          </button>
        </form>
      ) : (
        <div className="space-y-6">
          <input 
            type="file" 
            ref={fileInputRef} 
            onChange={handleFileChange} 
            accept=".csv" 
            className="hidden" 
          />
          <div 
            className="border-2 border-dashed border-slate-300 rounded-lg p-8 text-center bg-slate-50 hover:bg-slate-100 transition-colors cursor-pointer group" 
            onClick={() => fileInputRef.current?.click()}
          >
            <UploadCloud className="w-10 h-10 text-slate-400 mx-auto mb-2 group-hover:text-indigo-500" />
            <p className="text-sm font-medium text-slate-600">
              {bulkFile ? <span className="text-emerald-600 font-bold">{bulkFile}</span> : 'Click to Upload CSV'}
            </p>
            <p className="text-xs text-slate-400 mt-1">Supports .csv (Max 50MB)</p>
          </div>

          <button 
            onClick={handleBulkSimulate}
            disabled={isLoading || !isEnabled || !bulkFile}
            className="w-full bg-indigo-600 text-white font-semibold py-3 rounded-lg shadow-md hover:bg-indigo-700 focus:outline-none focus:ring-2 focus:ring-indigo-500 focus:ring-offset-2 disabled:opacity-50 flex items-center justify-center gap-2"
          >
             {isLoading && (
              <svg className="animate-spin h-5 w-5 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
              </svg>
            )}
            {isLoading ? 'Processing Batch...' : 'Run Bulk Prediction'}
          </button>
        </div>
      )}
    </div>
  );
};

export default PredictionForm;

import React, { useState, useEffect } from 'react';
import { TrainingMetrics, CustomerData } from '../types';
import { trainModel, generateMockDataset } from '../services/mlService';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer } from 'recharts';

interface TrainingPanelProps {
  onTrainingComplete: () => void;
}

const TrainingPanel: React.FC<TrainingPanelProps> = ({ onTrainingComplete }) => {
  const [isTraining, setIsTraining] = useState(false);
  const [progress, setProgress] = useState(0);
  const [metrics, setMetrics] = useState<TrainingMetrics | null>(null);
  const [dataset, setDataset] = useState<CustomerData[]>([]);

  useEffect(() => {
    // Load "Raw Data"
    setDataset(generateMockDataset(5));
  }, []);

  const handleTrain = async () => {
    setIsTraining(true);
    setProgress(0);

    // Simulate progress bar
    const interval = setInterval(() => {
      setProgress((prev) => {
        if (prev >= 90) return prev;
        return prev + 10;
      });
    }, 200);

    try {
      const results = await trainModel();
      clearInterval(interval);
      setProgress(100);
      setMetrics(results);
      onTrainingComplete();
    } catch (error) {
      console.error(error);
    } finally {
      setIsTraining(false);
    }
  };

  return (
    <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200 space-y-6">
      <div className="border-b border-slate-100 pb-4">
        <h2 className="text-xl font-semibold text-slate-800">1. Data Ingestion & Training</h2>
        <p className="text-sm text-slate-500 mt-1">
          Load raw customer data, preprocess features, and train the Random Forest Regressor.
        </p>
      </div>

      {/* Raw Data Preview */}
      <div className="space-y-3">
        <div className="flex justify-between items-center">
          <h3 className="text-sm font-medium text-slate-700">Raw Data Preview</h3>
          <span className="text-xs bg-slate-100 text-slate-600 px-2 py-1 rounded">10,000 records</span>
        </div>
        <div className="overflow-x-auto border rounded-lg">
          <table className="w-full text-sm text-left text-slate-600">
            <thead className="text-xs text-slate-700 uppercase bg-slate-50">
              <tr>
                <th className="px-4 py-3">Age</th>
                <th className="px-4 py-3">Loc</th>
                <th className="px-4 py-3">Income</th>
                <th className="px-4 py-3">Freq</th>
                <th className="px-4 py-3">AOV</th>
                <th className="px-4 py-3">Tenure</th>
              </tr>
            </thead>
            <tbody>
              {dataset.map((row, idx) => (
                <tr key={idx} className="border-b last:border-0 hover:bg-slate-50">
                  <td className="px-4 py-2">{row.age}</td>
                  <td className="px-4 py-2">{row.location}</td>
                  <td className="px-4 py-2">{row.incomeLevel}</td>
                  <td className="px-4 py-2">{row.purchaseFrequency.toFixed(1)}</td>
                  <td className="px-4 py-2">${row.avgOrderValue.toFixed(0)}</td>
                  <td className="px-4 py-2">{row.tenureDays}d</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      {/* Action Area */}
      <div className="flex flex-col md:flex-row gap-6 items-start">
        <button
          onClick={handleTrain}
          disabled={isTraining || !metrics}
          className={`px-6 py-3 rounded-lg font-medium text-white shadow-sm transition-all
            ${isTraining ? 'bg-indigo-400 cursor-not-allowed' : 
              metrics ? 'bg-emerald-600 hover:bg-emerald-700' : 'bg-indigo-600 hover:bg-indigo-700'}
          `}
        >
          {isTraining ? 'Training Model...' : metrics ? 'Model Trained' : 'Train Model'}
        </button>

        {isTraining && (
          <div className="flex-1 w-full pt-4">
             <div className="w-full bg-slate-200 rounded-full h-2.5">
              <div className="bg-indigo-600 h-2.5 rounded-full transition-all duration-300" style={{ width: `${progress}%` }}></div>
            </div>
            <p className="text-xs text-slate-500 mt-2 text-right">Running pipeline/train_pipeline.py...</p>
          </div>
        )}
      </div>

      {/* Metrics */}
      {metrics && (
        <div className="grid grid-cols-1 md:grid-cols-3 gap-4 animate-fade-in mt-4">
          <div className="bg-emerald-50 border border-emerald-100 p-4 rounded-lg">
            <p className="text-xs text-emerald-600 uppercase font-semibold">R² Score</p>
            <p className="text-2xl font-bold text-emerald-800">{metrics.r2Score}</p>
          </div>
          <div className="bg-slate-50 border border-slate-100 p-4 rounded-lg">
            <p className="text-xs text-slate-500 uppercase font-semibold">Mean Absolute Error</p>
            <p className="text-2xl font-bold text-slate-800">${metrics.mae}</p>
          </div>
          <div className="bg-slate-50 border border-slate-100 p-4 rounded-lg">
            <p className="text-xs text-slate-500 uppercase font-semibold">RMSE</p>
            <p className="text-2xl font-bold text-slate-800">{metrics.rmse}</p>
          </div>
        </div>
      )}
    </div>
  );
};

export default TrainingPanel;

