                  <td className="px-4 py-2">{row.purchaseFrequency.toFixed(1)}</td>
                  <td className="px-4 py-2">${row.avgOrderValue.toFixed(0)}</td>
                  <td className="px-4 py-2">{row.tenureDays}d</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      {/* Action Area */}
      <div className="flex flex-col md:flex-row gap-6 items-start">
        <button
          onClick={handleTrain}
          disabled={isTraining || metrics !== null}
          className={`px-6 py-3 rounded-lg font-medium text-white shadow-sm transition-all
            ${isTraining ? 'bg-indigo-400 cursor-not-allowed' : 
              metrics ? 'bg-emerald-600 cursor-default' : 'bg-indigo-600 hover:bg-indigo-700'}
          `}
        >
          {isTraining ? 'Training Model...' : metrics ? 'Model Trained' : 'Train Model'}
        </button>

        {isTraining && (
          <div className="flex-1 w-full pt-4">
             <div className="w-full bg-slate-200 rounded-full h-2.5">
              <div className="bg-indigo-600 h-2.5 rounded-full transition-all duration-300" style={{ width: `${progress}%` }}></div>
            </div>
            <p className="text-xs text-slate-500 mt-2 text-right">Running pipeline/train_pipeline.py...</p>
          </div>
        )}
      </div>

      {/* Metrics */}
      {metrics && (
        <div className="grid grid-cols-1 md:grid-cols-3 gap-4 animate-fade-in mt-4">
          <div className="bg-emerald-50 border border-emerald-100 p-4 rounded-lg">
            <p className="text-xs text-emerald-600 uppercase font-semibold">R² Score</p>
            <p className="text-2xl font-bold text-emerald-800">{metrics.r2Score}</p>
          </div>
          <div className="bg-slate-50 border border-slate-100 p-4 rounded-lg">
            <p className="text-xs text-slate-500 uppercase font-semibold">Mean Absolute Error</p>
            <p className="text-2xl font-bold text-slate-800">${metrics.mae}</p>
          </div>
          <div className="bg-slate-50 border border-slate-100 p-4 rounded-lg">
            <p className="text-xs text-slate-500 uppercase font-semibold">RMSE</p>
            <p className="text-2xl font-bold text-slate-800">{metrics.rmse}</p>
          </div>
        </div>
      )}
    </div>
  );
};

export default TrainingPanel;

import React, { useState, useRef } from 'react';
import { Gender, LocationType, IncomeLevel } from '../types';
import { predictCLV, predictBulk, parseAndCleanCSV } from '../services/mlService';
import { FileSpreadsheet, User, UploadCloud, Settings, Sliders, ChevronDown, AlertCircle, FileText } from 'lucide-react';

const PRESETS = {
  'Generic': { medium: 500, high: 2000 },
  'Fashion': { medium: 300, high: 1000 },     // High freq, lower value items
  'Electronics': { medium: 800, high: 2500 }, // Low freq, high value items
  'SaaS': { medium: 1000, high: 5000 }        // Recurring revenue focus
};

const PredictionForm = ({ onSingleResult, onBulkResult, isEnabled }) => {
  const [mode, setMode] = useState('single');
  const [isLoading, setIsLoading] = useState(false);
  const fileInputRef = useRef(null);

  // Configuration State
  const [industry, setIndustry] = useState('Generic');
  const [thresholds, setThresholds] = useState(PRESETS['Generic']);
  const [isConfigOpen, setIsConfigOpen] = useState(false);

  // Single Form State
  const [formData, setFormData] = useState({
    id: 'NEW-001',
    age: 30,
    gender: Gender.Female,
    location: LocationType.Urban,
    incomeLevel: IncomeLevel.Medium,
    purchaseFrequency: 5.0,
    avgOrderValue: 120.0,
    recencyDays: 10,
    tenureDays: 365,
    churned: 0
  });

  // Validation Error State
  const [errors, setErrors] = useState({});

  // Bulk Form State
  const [bulkFile, setBulkFile] = useState(null);
  const [selectedFileObj, setSelectedFileObj] = useState(null);

  const handleIndustryChange = (e) => {
    const newIndustry = e.target.value;
    setIndustry(newIndustry);
    setThresholds(PRESETS[newIndustry]);
  };

  const handleChange = (e) => {
    const { name, value } = e.target;

    // Clear error when user types
    if (errors[name]) {
      setErrors(prev => {
        const newErrors = { ...prev };
        delete newErrors[name];
        return newErrors;
      });
    }

    setFormData(prev => ({
      ...prev,
      [name]: (name === 'age' || name === 'recencyDays' || name === 'tenureDays' || name === 'churned') 
        ? parseInt(value) 
        : (name === 'purchaseFrequency' || name === 'avgOrderValue') 
          ? parseFloat(value) 
          : value
    }));
  };

  const handleFileChange = (e) => {
    const file = e.target.files?.[0];
    if (file) {
      setBulkFile(file.name);
      setSelectedFileObj(file);
    }
  };

  const validateForm = () => {
    const newErrors = {};

    if (formData.age < 18 || formData.age > 120) {
      newErrors.age = "Age must be 18-120";
    }
    if (formData.purchaseFrequency < 0) {
      newErrors.purchaseFrequency = "Must be ≥ 0";
    }
    if (formData.avgOrderValue < 0) {
      newErrors.avgOrderValue = "Must be ≥ 0";
    }
    if (formData.recencyDays < 0) {
      newErrors.recencyDays = "Must be ≥ 0";
    }
    if (formData.tenureDays < 0) {
      newErrors.tenureDays = "Must be ≥ 0";
    }

    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleSingleSubmit = async (e) => {
    e.preventDefault();
    if (!isEnabled) return;

    if (!validateForm()) return;

    setIsLoading(true);
    try {
      const result = await predictCLV(formData, thresholds);
      onSingleResult(result);
    } finally {
      setIsLoading(false);
    }
  };

  const handleBulkUpload = async () => {
    if (!isEnabled || !selectedFileObj) return;

    setIsLoading(true);
    try {
      // 1. Read File
      const text = await selectedFileObj.text();

      // 2. Parse & Auto-Clean
      const cleanedData = parseAndCleanCSV(text);

      if (cleanedData.length === 0) {
        alert("Could not parse data from CSV. Please check the format.");
        return;
      }

      // 3. Predict
      const result = await predictBulk(cleanedData, thresholds);
      onBulkResult(result);
    } catch (error) {
      console.error("Bulk processing failed", error);
      alert("Error processing file. Please ensure it is a valid CSV.");
    } finally {
      setIsLoading(false);
    }
  };

  const getInputClass = (fieldName) => `w-full border rounded-md px-3 py-2 text-sm text-black focus:outline-none focus:ring-2 disabled:bg-slate-100 disabled:text-slate-400 ${
    errors[fieldName] 
      ? 'border-red-500 focus:ring-red-500 bg-red-50' 
      : 'border-slate-300 bg-slate-50 focus:ring-indigo-500'
  }`;

  const labelClass = "block text-xs font-medium text-slate-700 mb-1";

  return (
    <div className={`bg-white p-6 rounded-xl shadow-sm border border-slate-200 transition-opacity ${!isEnabled ? 'opacity-50 pointer-events-none' : 'opacity-100'}`}>
      <div className="border-b border-slate-100 pb-4 mb-6">
        <h2 className="text-xl font-semibold text-slate-800">2. Prediction Pipeline</h2>
        <p className="text-sm text-slate-500 mt-1">
          Select input method to project Customer Lifetime Value Score.
        </p>
      </div>

      {/* Configuration Panel */}
      <div className="mb-6 bg-slate-50 rounded-lg border border-slate-200 p-4">
        <div className="flex justify-between items-center">
          <div className="flex items-center gap-2">
            <Settings className="w-4 h-4 text-indigo-600" />
            <span className="text-sm font-semibold text-slate-700">Segmentation Logic</span>
          </div>
          <button onClick={() => setIsConfigOpen(!isConfigOpen)} className="text-xs text-indigo-600 font-medium hover:text-indigo-800 hover:underline flex items-center gap-1 transition-colors">
            {isConfigOpen ? 'Hide Controls' : 'Customize'} <Sliders size={12}/>
          </button>
        </div>

        <div className="mt-3">
          {!isConfigOpen && (
             <div className="flex justify-between items-center text-xs text-slate-500">
               <div className="flex items-center gap-2">
                 <span className="font-medium text-slate-700">{industry} Mode:</span>
                 <span>Medium &gt; ${thresholds.medium}</span>
                 <span>High &gt; ${thresholds.high}</span>
               </div>
             </div>
          )}

          <div className={`space-y-4 overflow-hidden transition-all duration-300 ease-in-out ${isConfigOpen ? 'max-h-96 opacity-100 mt-4 pt-4 border-t border-slate-200' : 'max-h-0 opacity-0'}`}>
             <div>
                <label className="text-xs font-medium text-slate-500 block mb-1">Industry Context (Applies Presets)</label>
                <div className="relative">
                  <select 
                    value={industry} 
                    onChange={handleIndustryChange} 
                    className="w-full text-sm border border-slate-300 rounded-md shadow-sm px-3 py-2 bg-white focus:outline-none focus:border-indigo-500 focus:ring-1 focus:ring-indigo-500 appearance-none"
                  >
                    {Object.keys(PRESETS).map(k => <option key={k} value={k}>{k}</option>)}
                  </select>
                  <ChevronDown className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-400 w-4 h-4 pointer-events-none" />
                </div>
              </div>

              {/* Sliders */}
              <div className="space-y-4">
                <div>
                  <div className="flex justify-between text-xs mb-1">
                    <label className="font-medium text-slate-600">Medium Value Threshold</label>
                    <span className="font-bold text-amber-600">${thresholds.medium}</span>
                  </div>
                  <input type="range" min="0" max={thresholds.high} step="50" 
                      value={thresholds.medium}
                      onChange={(e) => setThresholds(prev => ({...prev, medium: Number(e.target.value)}))}
                      className="w-full h-2 bg-slate-200 rounded-lg appearance-none cursor-pointer accent-amber-500"
                  />
                  <p className="text-[10px] text-slate-400 mt-1">Customers with CLV above ${thresholds.medium} are marked Medium.</p>
                </div>
                <div>
                  <div className="flex justify-between text-xs mb-1">
                    <label className="font-medium text-slate-600">High Value Threshold</label>
                    <span className="font-bold text-emerald-600">${thresholds.high}</span>
                  </div>
                  <input type="range" min={thresholds.medium} max="10000" step="100" 
                      value={thresholds.high}
                      onChange={(e) => setThresholds(prev => ({...prev, high: Number(e.target.value)}))}
                      className="w-full h-2 bg-slate-200 rounded-lg appearance-none cursor-pointer accent-emerald-500"
                  />
                   <p className="text-[10px] text-slate-400 mt-1">Customers with CLV above ${thresholds.high} are marked High.</p>
                </div>
              </div>
          </div>
        </div>
      </div>

      {/* Mode Toggles */}
      <div className="flex p-1 bg-slate-100 rounded-lg mb-6">
        <button
          onClick={() => setMode('single')}
          className={`flex-1 flex items-center justify-center gap-2 py-2 text-sm font-medium rounded-md transition-all
            ${mode === 'single' ? 'bg-white text-indigo-700 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
        >
          <User size={16} /> Single Customer
        </button>
        <button
          onClick={() => setMode('bulk')}
          className={`flex-1 flex items-center justify-center gap-2 py-2 text-sm font-medium rounded-md transition-all
            ${mode === 'bulk' ? 'bg-white text-indigo-700 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
        >
          <FileSpreadsheet size={16} /> Bulk Upload
        </button>
      </div>

      {mode === 'single' ? (
        <form onSubmit={handleSingleSubmit} className="space-y-6">
           {/* Demographics */}
        <div className="space-y-4">
          <h3 className="text-sm font-semibold text-indigo-600 uppercase tracking-wide">Demographics</h3>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div>
              <label className={labelClass}>Age</label>
              <input 
                type="number" 
                name="age" 
                value={formData.age} 
                onChange={handleChange} 
                className={getInputClass('age')} 
              />
              {errors.age && <p className="text-red-500 text-xs mt-1 flex items-center gap-1"><AlertCircle size={10}/> {errors.age}</p>}
            </div>
            <div>
              <label className={labelClass}>Gender</label>
              <select name="gender" value={formData.gender} onChange={handleChange} className={getInputClass('gender')}>
                {Object.values(Gender).map(g => <option key={g} value={g}>{g}</option>)}
              </select>
            </div>
            <div>
              <label className={labelClass}>Location</label>
              <select name="location" value={formData.location} onChange={handleChange} className={getInputClass('location')}>
                {Object.values(LocationType).map(l => <option key={l} value={l}>{l}</option>)}
              </select>
            </div>
            <div>
              <label className={labelClass}>Income Level</label>
              <select name="incomeLevel" value={formData.incomeLevel} onChange={handleChange} className={getInputClass('incomeLevel')}>
                {Object.values(IncomeLevel).map(i => <option key={i} value={i}>{i}</option>)}
              </select>
            </div>
          </div>
        </div>

        {/* Behavior */}
        <div className="space-y-4">
          <h3 className="text-sm font-semibold text-indigo-600 uppercase tracking-wide">Behavioral Data</h3>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
             <div>
              <label className={labelClass}>Purchase Freq (orders/month)</label>
              <input 
                type="number" 
                step="0.1" 
                name="purchaseFrequency" 
                value={formData.purchaseFrequency} 
                onChange={handleChange} 
                className={getInputClass('purchaseFrequency')} 
              />
              {errors.purchaseFrequency && <p className="text-red-500 text-xs mt-1 flex items-center gap-1"><AlertCircle size={10}/> {errors.purchaseFrequency}</p>}
            </div>
            <div>
              <label className={labelClass}>Avg Order Value ($)</label>
              <input 
                type="number" 
                step="0.01" 
                name="avgOrderValue" 
                value={formData.avgOrderValue} 
                onChange={handleChange} 
                className={getInputClass('avgOrderValue')} 
              />
              {errors.avgOrderValue && <p className="text-red-500 text-xs mt-1 flex items-center gap-1"><AlertCircle size={10}/> {errors.avgOrderValue}</p>}
            </div>
            <div>
              <label className={labelClass}>Recency (days ago)</label>
              <input 
                type="number" 
                name="recencyDays" 
                value={formData.recencyDays} 
                onChange={handleChange} 
                className={getInputClass('recencyDays')} 
              />
              {errors.recencyDays && <p className="text-red-500 text-xs mt-1 flex items-center gap-1"><AlertCircle size={10}/> {errors.recencyDays}</p>}
            </div>
            <div>
              <label className={labelClass}>Tenure (days)</label>
              <input 
                type="number" 
                name="tenureDays" 
                value={formData.tenureDays} 
                onChange={handleChange} 
                className={getInputClass('tenureDays')} 
              />
              {errors.tenureDays && <p className="text-red-500 text-xs mt-1 flex items-center gap-1"><AlertCircle size={10}/> {errors.tenureDays}</p>}
            </div>
            <div className="md:col-span-2">
              <label className={labelClass}>Churn Status</label>
              <select name="churned" value={formData.churned} onChange={handleChange} className={getInputClass('churned')}>
                <option value={0}>Active</option>
                <option value={1}>Churned</option>
              </select>
            </div>
          </div>
        </div>

          <button 
            type="submit" 
            disabled={isLoading || !isEnabled}
            className="w-full bg-indigo-600 text-white font-semibold py-3 rounded-lg shadow-md hover:bg-indigo-700 focus:outline-none focus:ring-2 focus:ring-indigo-500 focus:ring-offset-2 disabled:opacity-50 flex items-center justify-center gap-2"
          >
            {isLoading && (
              <svg className="animate-spin h-5 w-5 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
              </svg>
            )}
            {isLoading ? 'Predicting CLV...' : 'Run Single Prediction'}
          </button>
        </form>
      ) : (
        <div className="space-y-6">
          <input 
            type="file" 
            ref={fileInputRef} 
            onChange={handleFileChange} 
            accept=".csv" 
            className="hidden" 
          />
          <div 
            className={`border-2 border-dashed rounded-lg p-8 text-center transition-colors cursor-pointer group relative
              ${bulkFile ? 'border-emerald-300 bg-emerald-50' : 'border-slate-300 bg-slate-50 hover:bg-slate-100'}
            `}
            onClick={() => fileInputRef.current?.click()}
          >
            {bulkFile ? (
               <div className="flex flex-col items-center">
                 <FileText className="w-10 h-10 text-emerald-600 mb-2" />
                 <p className="text-sm font-medium text-emerald-800 break-all">{bulkFile}</p>
                 <p className="text-xs text-emerald-600 mt-1">Ready to process</p>
               </div>
            ) : (
               <>
                <UploadCloud className="w-10 h-10 text-slate-400 mx-auto mb-2 group-hover:text-indigo-500" />
                <p className="text-sm font-medium text-slate-600">
                   Click to Upload CSV
                </p>
                <p className="text-xs text-slate-400 mt-1">Supports raw .csv (Auto-clean enabled)</p>
               </>
            )}
          </div>

          <button 
            onClick={handleBulkUpload}
            disabled={isLoading || !isEnabled || !bulkFile}
            className="w-full bg-indigo-600 text-white font-semibold py-3 rounded-lg shadow-md hover:bg-indigo-700 focus:outline-none focus:ring-2 focus:ring-indigo-500 focus:ring-offset-2 disabled:opacity-50 flex items-center justify-center gap-2"
          >
             {isLoading && (
              <svg className="animate-spin h-5 w-5 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
              </svg>
            )}
            {isLoading ? 'Processing & Predicting...' : 'Run Bulk Prediction'}
          </button>
        </div>
      )}
    </div>
  );
};

export default PredictionForm;

import React from 'react';

const BulkResultTable = ({ data }) => {

  const handleDownloadCSV = () => {
    if (!data.details || data.details.length === 0) return;

    const headers = [
      'Customer ID', 
      'Age', 
      'Gender', 
      'Location', 
      'Income Level', 
      'Purchase Frequency', 
      'Avg Order Value', 
      'Recency (Days)', 
      'Tenure (Days)', 
      'Churn Status', 
      'Predicted CLV', 
      'Segment'
    ];

    const csvRows = [headers.join(',')];

    data.details.forEach(row => {
      const values = [
        row.id,
        row.age,
        row.gender,
        row.location,
        row.incomeLevel,
        row.purchaseFrequency.toFixed(2),
        row.avgOrderValue.toFixed(2),
        row.recencyDays,
        row.tenureDays,
        row.churned === 1 ? 'Churned' : 'Active',
        row.predictedCLV.toFixed(2),
        row.segment
      ];
      // Simple CSV escaping for string fields if necessary, though current enums are safe
      csvRows.push(values.join(','));
    });

    const csvContent = csvRows.join('\n');
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const url = window.URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.setAttribute('download', `clv_predictions_${new Date().toISOString().split('T')[0]}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  return (
    <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden animate-fade-in">
      <div className="p-6 border-b border-slate-100 flex justify-between items-center bg-slate-50">
        <div>
           <h3 className="text-lg font-semibold text-slate-800">Bulk Analysis Results</h3>
           <p className="text-sm text-slate-500">Categorized list of {data.summary.totalCustomers} customers</p>
        </div>
        <button 
          onClick={handleDownloadCSV}
          className="text-indigo-600 hover:text-indigo-800 text-sm font-medium flex items-center gap-1"
        >
          <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
            <path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4"></path>
            <polyline points="7 10 12 15 17 10"></polyline>
            <line x1="12" y1="15" x2="12" y2="3"></line>
          </svg>
          Download CSV
        </button>
      </div>

      <div className="overflow-x-auto max-h-[500px] overflow-y-auto">
        <table className="w-full text-sm text-left text-slate-600">
          <thead className="text-xs text-slate-700 uppercase bg-slate-50 sticky top-0 shadow-sm z-10">
            <tr>
              <th className="px-6 py-3">Customer ID</th>
              <th className="px-6 py-3">Segment</th>
              <th className="px-6 py-3">Projected CLV Score</th>
              <th className="px-6 py-3">Income</th>
              <th className="px-6 py-3">Frequency</th>
              <th className="px-6 py-3">AOV</th>
              <th className="px-6 py-3">Status</th>
            </tr>
          </thead>
          <tbody>
            {data.details.sort((a,b) => b.predictedCLV - a.predictedCLV).map((customer) => (
              <tr key={customer.id} className="border-b last:border-0 hover:bg-slate-50 transition-colors">
                <td className="px-6 py-4 font-medium text-slate-900">{customer.id}</td>
                <td className="px-6 py-4">
                  <span className={`px-2 py-1 rounded-full text-xs font-semibold
                    ${customer.segment === 'High' ? 'bg-emerald-100 text-emerald-700' :
                      customer.segment === 'Medium' ? 'bg-amber-100 text-amber-700' : 
                      'bg-slate-100 text-slate-600'}
                  `}>
                    {customer.segment} Value
                  </span>
                </td>
                <td className="px-6 py-4 font-bold text-slate-800">
                  ${customer.predictedCLV.toLocaleString(undefined, {minimumFractionDigits: 2, maximumFractionDigits: 2})}
                </td>
                <td className="px-6 py-4">{customer.incomeLevel}</td>
                <td className="px-6 py-4">{customer.purchaseFrequency.toFixed(1)}</td>
                <td className="px-6 py-4">${customer.avgOrderValue.toFixed(0)}</td>
                <td className="px-6 py-4">
                    {customer.churned === 1 ? 
                        <span className="text-red-500 flex items-center gap-1"><span className="w-1.5 h-1.5 bg-red-500 rounded-full"></span>Churned</span> : 
                        <span className="text-emerald-600 flex items-center gap-1"><span className="w-1.5 h-1.5 bg-emerald-500 rounded-full"></span>Active</span>
                    }
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
};

export default BulkResultTable;

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
