/**
 * Calculates Customer Lifetime Value metrics based on inputs.
 * Model: Geometric retention model with profit margin.
 */
export const calculateMetrics = (inputs) => {
  const { avgOrderValue, purchaseFrequency, churnRate, profitMargin, acquisitionCost } = inputs;

  // 1. Basic Metrics
  const monthlyRevenue = avgOrderValue * purchaseFrequency;
  const annualRevenue = monthlyRevenue * 12;

  // 2. Lifetime Calculation (churnRate is percentage 0-100)
  // Expected lifespan in months = 1 / (churnRate / 100)
  // Cap lifespan at 60 months (5 years) for realistic projection if churn is very low
  const rawLifespanMonths = churnRate > 0 ? (1 / (churnRate / 100)) : 60; 
  const lifespanMonths = Math.min(rawLifespanMonths, 60); 

  // 3. CLV Calculations
  const grossLTV = monthlyRevenue * lifespanMonths;
  const netLTV = grossLTV * (profitMargin / 100);
  const profitAfterCAC = netLTV - acquisitionCost;
  const roi = acquisitionCost > 0 ? ((profitAfterCAC / acquisitionCost) * 100) : 0;

  // 4. Generate Projection Data (Monthly for 5 years)
  const projectionData = [];
  let cumulativeRevenue = 0;
  let cumulativeProfit = -acquisitionCost; // Start in the hole by CAC

  for (let month = 1; month <= 60; month++) {
    // Retention probability decay
    const retentionProb = Math.pow(1 - (churnRate / 100), month);

    const monthlyRev = monthlyRevenue * retentionProb;
    const monthlyProf = monthlyRev * (profitMargin / 100);

    cumulativeRevenue += monthlyRev;
    cumulativeProfit += monthlyProf;

    if (month % 3 === 0 || month === 1) { // Optimize data points
      projectionData.push({
        month: `M${month}`,
        revenue: Math.round(cumulativeRevenue),
        profit: Math.round(cumulativeProfit),
        baseline: 0
      });
    }
  }

  // Determine Customer Segment
  let segment = 'Low Value';
  if (netLTV > 5000) segment = 'VIP';
  else if (netLTV > 1500) segment = 'High Value';
  else if (netLTV > 500) segment = 'Mid Market';

  return {
    monthlyRevenue,
    annualRevenue,
    lifespanMonths,
    grossLTV,
    netLTV,
    profitAfterCAC,
    roi,
    segment,
    projectionData
  };
};

