          <div className="bg-slate-50 border border-slate-100 p-4 rounded-lg">
            <p className="text-xs text-slate-500 uppercase font-semibold">RMSE</p>
            <p className="text-2xl font-bold text-slate-800">{metrics.rmse}</p>
          </div>
        </div>
    </div>
  );
};

export default TrainingPanel;

export enum Gender {
  Male = 'Male',
  Female = 'Female'
}

export enum LocationType {
  Urban = 'Urban',
  Suburban = 'Suburban',
  Rural = 'Rural'
}

export enum IncomeLevel {
  Low = 'Low',
  Medium = 'Medium',
  High = 'High'
}

export type Industry = 'Generic' | 'Fashion' | 'Electronics' | 'SaaS';

export type CustomerSegment = 'High' | 'Medium' | 'Low';

export interface CustomerData {
  id: string;
  age: number;
  gender: Gender;
  location: LocationType;
  incomeLevel: IncomeLevel;
  purchaseFrequency: number;
  avgOrderValue: number;
  recencyDays: number;
  tenureDays: number;
  churned: number;
}

export interface SegmentationThresholds {
  medium: number;
  high: number;
}

export interface PredictionResult {
  clv: number;
  segment: CustomerSegment;
  confidence: number;
  inputData: CustomerData;
}

export interface BulkPredictionResult {
  summary: {
    totalCustomers: number;
    avgCLV: number;
    highCount: number;
    mediumCount: number;
    lowCount: number;
  };
  details: (CustomerData & { predictedCLV: number; segment: CustomerSegment })[];
}

export interface TrainingMetrics {
  r2Score: number;
  mae: number;
  rmse: number;
  samplesProcessed: number;
}

// --- E-COMMERCE MODELS (Operational Layer) ---

export interface Product {
  id: number;
  name: string;
  price: number;
  category: string;
